-- ----------------------------------------------------------------------------
-- Drop pass: every rulebook-owned view, reverse iteration order, CASCADE.
-- The rulebook is HEAD — the surviving view set must mirror it exactly.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_charge_interactions CASCADE;
DROP VIEW IF EXISTS vw_charges CASCADE;

-- ----------------------------------------------------------------------------
-- vw_charges: Individual charged particles with position and mass
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_charges CASCADE;
CREATE VIEW vw_charges WITH (security_invoker = ON) AS
SELECT
  t.charge_id,                                                                  -- Unique identifier
  t.label,                                                                      -- Human-readable label
  t.charge_value,                                                               -- Charge in Coulombs
  t.position_x,                                                                 -- X coordinate
  t.position_y,                                                                 -- Y coordinate
  t.position_z,                                                                 -- Z coordinate
  t.mass                                                                        -- Mass in kg
FROM charges t;

-- ----------------------------------------------------------------------------
-- vw_charge_interactions: Pairs of charges with computed electrostatic force
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_charge_interactions CASCADE;
CREATE VIEW vw_charge_interactions WITH (security_invoker = ON) AS
SELECT
  t.interaction_id,                                                             -- Interaction ID
  t.charge1_id,                                                                 -- First charge
  t.charge2_id,                                                                 -- Second charge
  calc_charge_interactions_is_repulsive(t.interaction_id) AS is_repulsive,      -- Same charge sign = repulsive
  calc_charge_interactions_is_attractive(t.interaction_id) AS is_attractive     -- Opposite charge sign = attractive
FROM charge_interactions t;

